//#region src/utils/errors/index.d.ts
/**
 * Pesafy error types — single source of truth.
 *
 * All codes map to a specific failure category so callers can handle
 * them without string-matching on the message.
 */
declare const ERROR_CODES: readonly ["AUTH_FAILED", "INVALID_CREDENTIALS", "INVALID_PHONE", "ENCRYPTION_FAILED", "VALIDATION_ERROR", "API_ERROR", "HTTP_ERROR", "NETWORK_ERROR", "REQUEST_FAILED", "INVALID_RESPONSE", "TIMEOUT", "RATE_LIMITED", "INSUFFICIENT_FUNDS", "TRANSACTION_FAILED", "DUPLICATE_REQUEST", "IDEMPOTENCY_ERROR"];
type ErrorCode = (typeof ERROR_CODES)[number];
interface PesafyErrorOptions {
  code: ErrorCode;
  message: string;
  /** HTTP status code from Daraja (if applicable) */
  statusCode?: number;
  /** Raw Daraja response body (for debugging) */
  response?: unknown;
  /** Underlying caught error (network, crypto, etc.) */
  cause?: unknown;
  /** Daraja requestId from the error envelope */
  requestId?: string;
  /** Whether this error is retryable */
  retryable?: boolean;
}
declare class PesafyError extends Error {
  readonly code: ErrorCode;
  readonly statusCode: number | undefined;
  readonly response: unknown;
  readonly requestId: string | undefined;
  readonly cause: unknown;
  readonly retryable: boolean;
  constructor(options: PesafyErrorOptions);
  /** Returns true if this is a validation error (user bug — do not retry) */
  get isValidation(): boolean;
  /** Returns true if this is an auth error */
  get isAuth(): boolean;
  toJSON(): {
    name: string;
    code: "AUTH_FAILED" | "INVALID_CREDENTIALS" | "INVALID_PHONE" | "ENCRYPTION_FAILED" | "VALIDATION_ERROR" | "API_ERROR" | "HTTP_ERROR" | "NETWORK_ERROR" | "REQUEST_FAILED" | "INVALID_RESPONSE" | "TIMEOUT" | "RATE_LIMITED" | "INSUFFICIENT_FUNDS" | "TRANSACTION_FAILED" | "DUPLICATE_REQUEST" | "IDEMPOTENCY_ERROR";
    message: string;
    statusCode: number | undefined;
    requestId: string | undefined;
    retryable: boolean;
  };
}
/** Convenience factory */
declare function createError(options: PesafyErrorOptions): PesafyError;
/** Type guard */
declare function isPesafyError(err: unknown): err is PesafyError;
//#endregion
//#region src/types/branded.d.ts
declare const __brand: unique symbol;
type Brand<T, B extends string> = T & {
  readonly [__brand]: B;
};
/**
 * A whole-number KES amount (Kenyan Shillings).
 * M-PESA only supports whole numbers — fractional shillings are rejected.
 */
type KesAmount = Brand<number, 'KesAmount'>;
/**
 * Creates a validated KesAmount.
 * @throws {TypeError} if amount is not a whole number ≥ 1
 */
declare function toKesAmount(value: number): KesAmount;
/**
 * A validated Kenyan MSISDN in Daraja format: 254XXXXXXXXX (12 digits).
 */
type MsisdnKE = Brand<string, 'MsisdnKE'>;
/**
 * Creates a validated MsisdnKE from any common Kenyan phone format.
 */
declare function toMsisdn(phone: string): MsisdnKE;
/** M-PESA Paybill shortcode */
type PaybillCode = Brand<string, 'PaybillCode'>;
/** M-PESA Till/Buy-Goods shortcode */
type TillCode = Brand<string, 'TillCode'>;
/** Any M-PESA shortcode (paybill, till, or B2C) */
type ShortCode = PaybillCode | TillCode | Brand<string, 'ShortCode'>;
declare function toPaybill(code: string | number): PaybillCode;
declare function toTill(code: string | number): TillCode;
declare function toShortCode(code: string | number): ShortCode;
/** M-PESA receipt number, e.g. "OEI2AK4XXXX" */
type MpesaReceiptNumber = Brand<string, 'MpesaReceiptNumber'>;
/** Daraja ConversationID */
type ConversationID = Brand<string, 'ConversationID'>;
/** Daraja OriginatorConversationID */
type OriginatorConversationID = Brand<string, 'OriginatorConversationID'>;
/** Daraja CheckoutRequestID (STK Push) */
type CheckoutRequestID = Brand<string, 'CheckoutRequestID'>;
/**
 * A discriminated union result — either Ok<T> or Err<E>.
 * Prefer this over throwing in application-level code.
 *
 * @example
 * const result = await mpesa.stkPushSafe({ ... });
 * if (result.ok) {
 *   console.log(result.data.CheckoutRequestID);
 * } else {
 *   console.error(result.error.code, result.error.message);
 * }
 */
type Result<T, E = PesafyError> = {
  readonly ok: true;
  readonly data: T;
} | {
  readonly ok: false;
  readonly error: E;
};
declare function ok<T>(data: T): Result<T, never>;
declare function err<E>(error: E): Result<never, E>;
/** Makes all properties deeply readonly */
type DeepReadonly<T> = { readonly [K in keyof T]: T[K] extends object ? DeepReadonly<T[K]> : T[K] };
/** Strict pick — only allows known keys */
type StrictPick<T, K extends keyof T> = Pick<T, K>;
/** Non-empty string */
type NonEmptyString = Brand<string, 'NonEmptyString'>;
declare function toNonEmpty(s: string): NonEmptyString;
//#endregion
//#region src/mpesa/account-balance/types.d.ts
/**
 * Account Balance Query types
 *
 * API: POST /mpesa/accountbalance/v1/query
 *
 * Queries the current balance of an M-PESA shortcode.
 * This is ASYNCHRONOUS — final results are POSTed to your ResultURL.
 *
 * Required org portal role: "Account Balance ORG API initiator"
 *
 * Ref: Account Balance — Daraja Developer Portal
 */
interface AccountBalanceRequest {
  /**
   * Your business shortcode from which balance is queried.
   * Daraja field: PartyA
   */
  partyA: string;
  /**
   * Type of the PartyA identifier.
   *   "1" = MSISDN
   *   "2" = Till Number
   *   "4" = Organisation ShortCode (most common — Paybill/B2C)
   * Daraja field: IdentifierType
   */
  identifierType: '1' | '2' | '4';
  /**
   * URL where Safaricom POSTs the balance result.
   * Must be publicly accessible. HTTPS required in production.
   * Daraja field: ResultURL
   */
  resultUrl: string;
  /**
   * URL Safaricom calls when the request times out.
   * Daraja field: QueueTimeOutURL
   */
  queueTimeOutUrl: string;
  /**
   * Short remarks (up to 100 characters).
   * Daraja field: Remarks
   */
  remarks?: string;
}
interface AccountBalanceResponse {
  OriginatorConversationID: string;
  ConversationID: string;
  /** "0" = request accepted */
  ResponseCode: string;
  ResponseDescription: string;
}
/**
 * Balance data for a single account type.
 *
 * M-PESA shortcodes can have multiple account types, each returned separately.
 * Format: "AccountName|Currency|Amount"
 * Example: "Working Account|KES|1450.00|KES|0.00|KES|0.00"
 */
interface AccountBalanceData {
  /** Raw pipe-delimited string from Daraja */
  rawBalance: string;
  /** Parsed accounts */
  accounts: ParsedAccount[];
}
interface ParsedAccount {
  name: string;
  currency: string;
  /** Amount as a string (Daraja sends decimals) */
  amount: string;
}
interface AccountBalanceResult {
  Result: {
    ResultType: string; /** 0 = success */
    ResultCode: number;
    ResultDesc: string;
    OriginatorConversationID: string;
    ConversationID: string;
    TransactionID: string;
    ResultParameters?: {
      ResultParameter: Array<{
        Key: string;
        Value: string | number;
      }>;
    };
    ReferenceData?: {
      ReferenceItem: {
        Key: string;
        Value: string;
      } | Array<{
        Key: string;
        Value: string;
      }>;
    };
  };
}
/**
 * Parses the raw Daraja balance string into structured account objects.
 *
 * Daraja returns balance as: "Working Account|KES|500.00|Utility Account|KES|0.00"
 * (each account is 3 pipe-separated fields repeated).
 */
declare function parseAccountBalance(raw: string): ParsedAccount[];
/**
 * Extracts the account balance result parameter by key.
 */
declare function getAccountBalanceParam(result: AccountBalanceResult, key: string): string | number | undefined;
/**
 * Returns true if the Account Balance result is successful.
 */
declare function isAccountBalanceSuccess(result: AccountBalanceResult): boolean;
//#endregion
//#region src/mpesa/b2b-express-checkout/types.d.ts
/**
 * src/mpesa/b2b-express-checkout/types.ts
 *
 * B2B Express Checkout (USSD Push to Till) type definitions.
 * Strictly aligned with Safaricom Daraja B2B Express Checkout API documentation.
 *
 * Endpoint: POST https://sandbox.safaricom.co.ke/v1/ussdpush/get-msisdn
 *
 * Flow:
 *   1. Vendor initiates USSD push via Daraja
 *   2. Merchant receives USSD prompt on their till
 *   3. Merchant enters Operator ID + M-PESA PIN
 *   4. M-PESA debits merchant, credits vendor
 *   5. Daraja POSTs callback to your callbackUrl
 */
/**
 * Request payload for B2B Express Checkout USSD Push.
 *
 * Daraja payload shape (all field names are camelCase except RequestRefID):
 * {
 *   "primaryShortCode": "000001",
 *   "receiverShortCode": "000002",
 *   "amount":            "100",          ← sent as string per Daraja spec
 *   "paymentRef":        "paymentRef",
 *   "callbackUrl":       "https://...",
 *   "partnerName":       "Vendor",
 *   "RequestRefID":      "uuid"          ← PascalCase per Daraja spec
 * }
 */
interface B2BExpressCheckoutRequest {
  /**
   * Debit party — the merchant's till number that will be charged.
   * Daraja field: primaryShortCode
   */
  primaryShortCode: string;
  /**
   * Credit party — the vendor's Paybill account that will receive funds.
   * Daraja field: receiverShortCode
   */
  receiverShortCode: string;
  /**
   * Amount to send. Must be a whole number ≥ 1.
   * Sent as a string in the Daraja payload (e.g. "100").
   * Daraja field: amount
   */
  amount: number;
  /**
   * Payment reference shown in the merchant's USSD prompt.
   * Daraja field: paymentRef
   */
  paymentRef: string;
  /**
   * Publicly accessible URL where Daraja POSTs the transaction result.
   * Daraja field: callbackUrl
   */
  callbackUrl: string;
  /**
   * Vendor's friendly name shown in the merchant's USSD prompt:
   * "You are about to send Ksh {{amount}} to {{partnerName}}..."
   * Daraja field: partnerName
   */
  partnerName: string;
  /**
   * Unique identifier for this request — used for idempotency.
   * Auto-generated (UUID v4) if not provided.
   * Daraja field: RequestRefID (PascalCase per Daraja spec)
   */
  requestRefId?: string;
}
/**
 * Synchronous acknowledgement returned immediately by Daraja.
 *
 * Daraja response shape:
 * {
 *   "code":   "0",
 *   "status": "USSD Initiated Successfully"
 * }
 *
 * code "0" means the USSD push was initiated. The actual transaction result
 * comes later via the callbackUrl.
 */
interface B2BExpressCheckoutResponse {
  /** "0" = USSD push initiated successfully */
  code: string;
  /** Human-readable status, e.g. "USSD Initiated Successfully" */
  status: string;
}
/**
 * Callback when the merchant CANCELLED the USSD prompt.
 *
 * Daraja callback shape:
 * {
 *   "resultCode":       "4001",
 *   "resultDesc":       "User cancelled transaction",
 *   "requestId":        "c2a9ba32-9e11-4b90-892c-7bc54944609a",
 *   "amount":           "71.0",
 *   "paymentReference": "MAndbubry3hi"
 * }
 */
interface B2BExpressCheckoutCallbackCancelled {
  /** "4001" for user cancellation */
  resultCode: string;
  resultDesc: string;
  requestId: string;
  /** Amount as a string, e.g. "71.0" */
  amount: string;
  /** The payment reference from the original request */
  paymentReference: string;
}
/**
 * Callback when the M-PESA transaction SUCCEEDED.
 *
 * Daraja callback shape:
 * {
 *   "resultCode":    "0",
 *   "resultDesc":    "The service request is processed successfully.",
 *   "amount":        "71.0",
 *   "requestId":     "404e1aec-19e0-4ce3-973d-bd92e94c8021",
 *   "resultType":    "0",
 *   "conversationID":"AG_20230426_2010434680d9f5a73766",
 *   "transactionId": "RDQ01NFT1Q",
 *   "status":        "SUCCESS"
 * }
 */
interface B2BExpressCheckoutCallbackSuccess {
  /** "0" */
  resultCode: string;
  resultDesc: string;
  /** Amount as a string, e.g. "71.0" */
  amount: string;
  requestId: string;
  /** Usually "0" */
  resultType: string;
  /** M-PESA conversation ID, e.g. "AG_20230426_..." */
  conversationID: string;
  /** M-PESA receipt number, e.g. "RDQ01NFT1Q" */
  transactionId: string;
  /** "SUCCESS" */
  status: string;
}
/**
 * Callback for any non-zero, non-cancelled failure
 * (e.g. KYC failure, USSD network error, missing nominated number).
 *
 * Error codes documented by Daraja:
 *   4102 — Merchant KYC failure
 *   4104 — Missing nominated number
 *   4201 — USSD network error
 *   4203 — USSD exception error
 */
interface B2BExpressCheckoutCallbackFailed {
  resultCode: string;
  resultDesc: string;
  requestId: string;
  amount: string;
}
/**
 * Union of all possible callback payload shapes.
 * Discriminate on `resultCode`:
 *   "0"    → B2BExpressCheckoutCallbackSuccess
 *   "4001" → B2BExpressCheckoutCallbackCancelled
 *   other  → B2BExpressCheckoutCallbackFailed
 */
type B2BExpressCheckoutCallback = B2BExpressCheckoutCallbackSuccess | B2BExpressCheckoutCallbackCancelled | B2BExpressCheckoutCallbackFailed;
/**
 * Known B2B Express Checkout result codes.
 *
 * SUCCESS  (0)    — Transaction completed successfully
 * CANCELLED(4001) — Merchant cancelled the USSD prompt
 * KYC_FAIL (4102) — Merchant KYC failure; provide valid KYC
 * NO_NUMBER(4104) — Missing nominated number; configure in M-PESA portal
 * NET_ERROR(4201) — USSD network error; retry on stable network
 * USSD_ERR (4203) — USSD exception error; retry on stable network
 */
declare const B2B_RESULT_CODES: {
  readonly SUCCESS: "0";
  readonly CANCELLED: "4001";
  readonly KYC_FAIL: "4102";
  readonly NO_NOMINATED_NUMBER: "4104";
  readonly USSD_NETWORK_ERROR: "4201";
  readonly USSD_EXCEPTION_ERROR: "4203";
};
type B2BResultCode = (typeof B2B_RESULT_CODES)[keyof typeof B2B_RESULT_CODES];
/**
 * B2B Express Checkout error codes.
 * `(string & {})` keeps these literals in IntelliSense while still accepting
 * unknown codes without triggering no-redundant-type-constituents.
 */
type B2BExpressCheckoutErrorCode = B2BResultCode | (string & {});
/**
 * Synchronous error response from Daraja when the request itself fails
 * (before the USSD is initiated).
 */
interface B2BExpressCheckoutErrorResponse {
  requestId: string;
  errorCode: B2BExpressCheckoutErrorCode;
  errorMessage: string;
}
